import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import {
  generateRSAKeyPair, generateRSASignKeyPair, generateECDHKeyPair,
  exportSignPublicKeyPEM, exportECDHPublicKeyPEM, saveKeysToSession
} from '../utils/crypto';
import styles from './Auth.module.css';

export default function RegisterPage() {
  const [form,    setForm]    = useState({ username:'', email:'', password:'', confirm:'' });
  const [error,   setError]   = useState('');
  const [loading, setLoading] = useState(false);
  const { register }      = useAuth();
  const { theme, toggle } = useTheme();
  const navigate          = useNavigate();

  const handle = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const submit = async e => {
    e.preventDefault(); setError('');
    if (form.password !== form.confirm) { setError('Passwords do not match'); return; }
    if (form.password.length < 8)       { setError('Password must be at least 8 characters'); return; }
    setLoading(true);
    try {
      const rsaEncPair  = await generateRSAKeyPair();
      const rsaSignPair = await generateRSASignKeyPair();
      const ecdhPair    = await generateECDHKeyPair();
      const public_key      = await exportSignPublicKeyPEM(rsaSignPair.publicKey);
      const ecdh_public_key = await exportECDHPublicKeyPEM(ecdhPair.publicKey);
      await saveKeysToSession(rsaEncPair, rsaSignPair, ecdhPair);
      await register({ username: form.username, email: form.email,
                       password: form.password, public_key, ecdh_public_key });
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.error || 'Registration failed');
    } finally { setLoading(false); }
  };

  return (
    <div className={styles.page}>
      <button className={styles.themeBtn} onClick={toggle}>{theme==='light'?'🌙':'☀️'}</button>
      <div className={styles.card}>
        <div className={styles.logo}>🔐</div>
        <h1 className={styles.title}>CipherLink</h1>
        <p className={styles.subtitle}>Create your secure account</p>
        <form onSubmit={submit} className={styles.form}>
          <div className={styles.field}>
            <label>Username</label>
            <input name="username" value={form.username} onChange={handle}
                   placeholder="Choose username" required minLength={3} />
          </div>
          <div className={styles.field}>
            <label>Email</label>
            <input name="email" type="email" value={form.email} onChange={handle}
                   placeholder="your@email.com" required />
          </div>
          <div className={styles.field}>
            <label>Password</label>
            <input name="password" type="password" value={form.password} onChange={handle}
                   placeholder="Min 8 characters" required />
          </div>
          <div className={styles.field}>
            <label>Confirm Password</label>
            <input name="confirm" type="password" value={form.confirm} onChange={handle}
                   placeholder="Repeat password" required />
          </div>
          {error   && <div className={styles.error}>{error}</div>}
          {loading && <div className={styles.info}>🔑 Generating cryptographic keys…</div>}
          <button type="submit" className={styles.btn} disabled={loading}>
            {loading ? 'Generating Keys & Registering...' : 'Create Account'}
          </button>
        </form>
        <p className={styles.link}>Already have an account? <Link to="/login">Sign in</Link></p>
        <div className={styles.secBadge}>🛡️ Keys generated locally — never sent to server</div>
      </div>
    </div>
  );
}
